    {
        "q": "What keyword defines a function?",
        "choices": ["func", "def", "function"],
        "answer": 1,
    },
    {
        "q": "Which one stores key-value pairs?",
        "choices": ["list", "dict", "tuple"],
        "answer": 1,
    },
]

print("Loaded", len(questions), "questions!")

class QuizGame:
    def __init__(self, questions):
        self.questions = questions
        self.score = 0

    def ask(self, item):
        print(item["q"])
        for i, choice in enumerate(item["choices"]):
            print(f"  {i}: {choice}")
        # pretend the player picked the correct answer for this demo
        guess = item["answer"]
        if guess == item["answer"]:
            print("Correct! ✅")
            self.score += 1
        else:
            print("Nope. ❌")

    def play(self):
        for item in self.questions:
            self.ask(item)
        total = len(self.questions)
        print(f"\nFinal score: {self.score}/{total}")

game = QuizGame([{"q": "2+2?", "choices": ["3", "4"], "answer": 1}])
game.play()

